B.WF=new A.b8("luke-lesson-1","path-luke","\ud558\ub098\ub2d8\uc758 \uacc4\ud68d\uacfc \uc57d\uc18d\uc758 \uc2dc\uc791","\ub204\uac00\ubcf5\uc74c 1\uc7a5","\ub204\uac00\ubcf5\uc74c\uc740 \uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd \uc774\uc57c\uae30\ub97c \uc790\uc138\ud558\uac8c \uae30\ub85d\ud558\uba70 \uc2dc\uc791\ud574\uc694. \uc138\ub840 \uc694\ud55c\uc758 \ucd9c\uc0dd\uc774 \uba3c\uc800 \uc608\uace0\ub418\uace0, \uc774\uc5b4\uc11c \ucc9c\uc0ac\uac00 \ub9c8\ub9ac\uc544\uc5d0\uac8c \ub098\ud0c0\ub098 \uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd\uc744 \uc54c\ub9ac\uc8e0.","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \uacc4\ud68d\uc744 \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?")
B.Wj=new A.b8("luke-lesson-2","path-luke","\uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd\uacfc \ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ud558\uc2ec","\ub204\uac00\ubcf5\uc74c 2\uc7a5","\uc608\uc218\ub2d8\uc740 \ubca0\ub4e4\ub808\ud5f4\uc5d0\uc11c \ud0dc\uc5b4\ub098\uc2dc\uace0, \ucc9c\uc0ac\ub4e4\uc740 \ubaa9\uc790\ub4e4\uc5d0\uac8c \uadf8 \uc18c\uc2dd\uc744 \uc804\ud574\uc694. \ubaa9\uc790\ub4e4\uc740 \uc989\uc2dc \ucc3e\uc544\uac00 \uc544\uae30 \uc608\uc218\ub2d8\uc744 \uacbd\ubc30\ud558\uba70 \uae30\uc068\uc73c\ub85c \ub3cc\uc544\uac00\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc774 \ud558\uc2dc\ub294 \uc77c\uc744 \uc54c\uc544\ubcf4\uace0 \uc788\ub098\uc694?")
B.WX=new A.b8("luke-lesson-3","path-luke","\ud68c\uac1c\uc640 \uc900\ube44\ub41c \ub9c8\uc74c","\ub204\uac00\ubcf5\uc74c 3\uc7a5","\uc138\ub840 \uc694\ud55c\uc740 \uc0ac\ub78c\ub4e4\uc5d0\uac8c \ud68c\uac1c\ub97c \uc120\ud3ec\ud558\uba70 \ud558\ub098\ub2d8 \ub098\ub77c\ub97c \uc900\ube44\ud558\ub77c\uace0 \ub9d0\ud574\uc694. \ub2e8\uc21c\ud55c \ub9d0\uc774 \uc544\ub2c8\ub77c \uc0b6\uc758 \ubcc0\ud654, \uc989 \uc5f4\ub9e4 \ub9fa\ub294 \ud68c\uac1c\ub97c \uac15\uc870\ud574\uc694.","\ub098\ub294 \uc9c4\uc9dc\ub85c \ubcc0\ud654\ub418\uace0 \uc788\ub098\uc694?")
B.Xi=new A.b8("luke-lesson-4","path-luke","\uc2dc\ud5d8\uacfc \uc0ac\uba85\uc758 \uc2dc\uc791","\ub204\uac00\ubcf5\uc74c 4\uc7a5","\uc608\uc218\ub2d8\uc740 \uc131\ub839\uc5d0 \uc774\ub04c\ub824 \uad11\uc57c\uc5d0\uc11c \uc2dc\ud5d8\uc744 \ubc1b\uc73c\uc138\uc694. \ub9c8\uadc0\ub294 \uc5ec\ub7ec \ubc29\uc2dd\uc73c\ub85c \uc720\ud639\ud558\uc9c0\ub9cc \uc608\uc218\ub2d8\uc740 \ub9d0\uc500\uc73c\ub85c \uc774\uae30\uc138\uc694.","\ub098\ub294 \uc720\ud639 \uc55e\uc5d0\uc11c \uc5b4\ub5bb\uac8c \ubc18\uc751\ud558\uace0 \uc788\ub098\uc694?")
B.WW=new A.b8("luke-lesson-5","path-luke","\ubd80\ub974\uc2ec\uacfc \uc21c\uc885","\ub204\uac00\ubcf5\uc74c 5\uc7a5","\uc608\uc218\ub2d8\uc740 \uc5b4\ubd80\ub4e4\uc744 \ubd80\ub974\uc2dc\uace0 \uadf8\ub4e4\uc740 \ubaa8\ub4e0 \uac83\uc744 \ub0b4\ub824\ub193\uace0 \ub530\ub974\uc138\uc694. \ubca0\ub4dc\ub85c\ub294 \uc790\uc2e0\uc758 \ubd80\uc871\ud568\uc744 \uae68\ub2eb\uace0 \uc608\uc218\ub2d8 \uc55e\uc5d0 \uc5ce\ub4dc\ub824\uc694.","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \ubd80\ub974\uc2ec\uc5d0 \uc5b4\ub5bb\uac8c \ubc18\uc751\ud558\uace0 \uc788\ub098\uc694?")
B.X4=new A.b8("luke-lesson-6","path-luke","\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uae30\uc900\uacfc \uc0b6","\ub204\uac00\ubcf5\uc74c 6\uc7a5","\uc608\uc218\ub2d8\uc740 \uc548\uc2dd\uc77c\uc5d0 \ub300\ud574 \uac00\ub974\uce58\uc2dc\uba70 \ud615\uc2dd\ubcf4\ub2e4 \uc0ac\ub78c\uc744 \uc0b4\ub9ac\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694. \uc5f4\ub450 \uc81c\uc790\ub97c \uc138\uc6b0\uc2dc\uace0 \ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uae30\uc900\uc744 \uac00\ub974\uce58\uc138\uc694.","\ub098\ub294 \uc5b4\ub5a4 \uae30\uc900\uc73c\ub85c \uc0b4\uc544\uac00\uace0 \uc788\ub098\uc694?")
B.WE=new A.b8("luke-lesson-7","path-luke","\ubbff\uc74c\uacfc \uc0ac\ub791\uc758 \ubc18\uc751","\ub204\uac00\ubcf5\uc74c 7\uc7a5","\ubc31\ubd80\uc7a5\uc740 \ub9d0\uc500\ub9cc\uc73c\ub85c\ub3c4 \uce58\uc720\ud558\uc2e4 \uac83\uc744 \ubbff\ub294 \ud070 \ubbff\uc74c\uc744 \ubcf4\uc5ec\uc918\uc694. \uc608\uc218\ub2d8\uc740 \uacfc\ubd80\uc758 \uc544\ub4e4\uc744 \uc0b4\ub9ac\uc2dc\uba70 \uae0d\ud73c\uc744 \ub098\ud0c0\ub0b4\uc138\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc5bc\ub9c8\ub098 \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?")
B.WY=new A.b8("luke-lesson-8","path-luke","\ub9d0\uc500\uacfc \ubbff\uc74c\uc758 \ubc18\uc751","\ub204\uac00\ubcf5\uc74c 8\uc7a5","\uc528 \ubfcc\ub9ac\ub294 \ube44\uc720\ub97c \ud1b5\ud574 \ub9c8\uc74c \uc0c1\ud0dc\uc5d0 \ub530\ub77c \ub9d0\uc500\uc774 \ub2e4\ub974\uac8c \ubc1b\uc544\ub4e4\uc5ec\uc9c4\ub2e4\uace0 \uac00\ub974\uce58\uc138\uc694. \ud3ed\ud48d\uc744 \uc7a0\uc7a0\ud558\uac8c \ud558\uc2dc\uba70 \ubbff\uc74c\uc744 \uac00\ub974\uce58\uc2dc\uace0 \uadc0\uc2e0 \ub4e4\ub9b0 \uc0ac\ub78c\uc744 \uace0\uce58\uc138\uc694.","\ub098\ub294 \ub9d0\uc500\uc744 \uc5b4\ub5bb\uac8c \ubc1b\uc544\ub4e4\uc774\uace0 \uc788\ub098\uc694?")
B.Xf=new A.b8("luke-lesson-9","path-luke","\uc81c\uc790\uc758 \uae38\uacfc \ub530\ub984\uc758 \uc758\ubbf8","\ub204\uac00\ubcf5\uc74c 9\uc7a5","\uc608\uc218\ub2d8\uc740 \uc81c\uc790\ub4e4\uc744 \ubcf4\ub0b4\uc2dc\uba70 \ud558\ub098\ub2d8 \ub098\ub77c\ub97c \uc804\ud558\uac8c \ud558\uc138\uc694. \uc624\ubcd1\uc774\uc5b4 \uae30\uc801\uc744 \ud1b5\ud574 \ud558\ub098\ub2d8\uc758 \ub2a5\ub825\uc744 \ubcf4\uc5ec\uc8fc\uc2dc\uace0 \ubca0\ub4dc\ub85c\ub294 \uc608\uc218\ub2d8\uc744 \uadf8\ub9ac\uc2a4\ub3c4\ub85c \uace0\ubc31\ud574\uc694.","\ub098\ub294 \uc608\uc218\ub2d8\uc744 \ub204\uad6c\ub77c\uace0 \uace0\ubc31\ud558\uace0 \uc788\ub098\uc694?")
B.Xd=new A.b8("luke-lesson-10","path-luke","\uc0ac\ub791\uacfc \uc12c\uae40\uc758 \uc0b6","\ub204\uac00\ubcf5\uc74c 10\uc7a5","\uc608\uc218\ub2d8\uc740 70\uc778\uc744 \ubcf4\ub0b4\uc2dc\uba70 \ubcf5\uc74c\uc744 \uc804\ud558\uac8c \ud558\uc138\uc694. \uc0ac\uc5ed\uc744 \ud1b5\ud574 \uae30\uc068\uc744 \uacbd\ud5d8\ud558\uc9c0\ub9cc \uc608\uc218\ub2d8\uc740 \ud558\ub098\ub2d8\uacfc\uc758 \uad00\uacc4\ub97c \ub354 \uc911\uc694\ud558\uac8c \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \uc9c4\uc9dc\ub85c \uc0ac\ub791\uc744 \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?")
B.Wb=new A.b8("luke-lesson-11","path-luke","\uae30\ub3c4\uc640 \ub9c8\uc74c\uc758 \uc0c1\ud0dc","\ub204\uac00\ubcf5\uc74c 11\uc7a5","\uc608\uc218\ub2d8\uc740 \uc81c\uc790\ub4e4\uc5d0\uac8c \uae30\ub3c4\ub97c \uac00\ub974\uce58\uc2dc\uba70 \ud558\ub098\ub2d8\uacfc\uc758 \uad00\uacc4\ub97c \ubcf4\uc5ec\uc8fc\uc138\uc694. \uad6c\ud558\uace0 \ucc3e\uace0 \ub450\ub4dc\ub9ac\ub77c\uace0 \ub9d0\uc500\ud558\uc2dc\uba70 \ub048\uc9c8\uae34 \uae30\ub3c4\uc758 \uc911\uc694\uc131\uc744 \uac15\uc870\ud558\uc138\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uacfc \ub300\ud654\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694?")
B.X5=new A.b8("luke-lesson-12","path-luke","\ub450\ub824\uc6c0\uc774 \uc544\ub2cc \ud558\ub098\ub2d8\uc744 \ubc14\ub77c\ubcf4\ub294 \uc0b6","\ub204\uac00\ubcf5\uc74c 12\uc7a5","\uc608\uc218\ub2d8\uc740 \uc678\uc2dd\uacfc \uc704\uc120\uc744 \uacbd\uace0\ud558\uc2dc\uba70 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \ub4dc\ub7ec\ub0a0 \uac83\uc744 \ub9d0\uc500\ud558\uc138\uc694. \uc0ac\ub78c\uc744 \ub450\ub824\uc6cc\ud558\uc9c0 \ub9d0\uace0 \ud558\ub098\ub2d8\uc744 \ub450\ub824\uc6cc\ud558\ub77c\uace0 \uac00\ub974\uce58\uc138\uc694.","\ub098\ub294 \ubb34\uc5c7\uc744 \uac00\uc7a5 \ub450\ub824\uc6cc\ud558\uace0 \uc788\ub098\uc694?")
B.WB=new A.b8("luke-lesson-13","path-luke","\ud68c\uac1c\uc640 \ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uc131\uc7a5","\ub204\uac00\ubcf5\uc74c 13\uc7a5","\uc608\uc218\ub2d8\uc740 \ud68c\uac1c\ud558\uc9c0 \uc54a\uc73c\uba74 \uba78\ub9dd\ud560 \uc218\ubc16\uc5d0 \uc5c6\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694. \uc5f4\ub9e4 \ub9fa\uc9c0 \ubabb\ud558\ub294 \ubb34\ud654\uacfc\ub098\ubb34 \ube44\uc720\ub97c \ud1b5\ud574 \uae30\ud68c\ub97c \uc8fc\uc2dc\ub294 \ud558\ub098\ub2d8\uc758 \uc778\ub0b4\ub97c \ubcf4\uc5ec\uc8fc\uc138\uc694.","\ub098\ub294 \uc9c0\uae08 \ubcc0\ud654\ub418\uace0 \uc788\ub098\uc694?")
B.WC=new A.b8("luke-lesson-14","path-luke","\uacb8\uc190\uacfc \uc81c\uc790\uc758 \ub300\uac00","\ub204\uac00\ubcf5\uc74c 14\uc7a5","\uc608\uc218\ub2d8\uc740 \uc794\uce58 \uc790\ub9ac\uc5d0\uc11c \uacb8\uc190\ud568\uc744 \uac00\ub974\uce58\uc138\uc694. \ub0ae\uc740 \uc790\ub97c \ucd08\ub300\ud558\ub77c\uace0 \ud558\uc2dc\uba70 \ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uad00\uc744 \ubcf4\uc5ec\uc8fc\uc138\uc694.","\ub098\ub294 \uacb8\uc190\ud55c \ud0dc\ub3c4\ub85c \uc0b4\uace0 \uc788\ub098\uc694?")
B.WS=new A.b8("luke-lesson-15","path-luke","\uc783\uc740 \uc790\ub97c \ucc3e\uc73c\uc2dc\ub294 \ud558\ub098\ub2d8","\ub204\uac00\ubcf5\uc74c 15\uc7a5","\uc608\uc218\ub2d8\uc740 \uc783\uc740 \uc591, \uc783\uc740 \ub4dc\ub77c\ud06c\ub9c8, \ub3cc\uc544\uc628 \uc544\ub4e4\uc758 \ube44\uc720\ub97c \ud1b5\ud574 \ud558\ub098\ub2d8\uc758 \ub9c8\uc74c\uc744 \ubcf4\uc5ec\uc8fc\uc138\uc694. \ud558\ub098\ub2d8\uc740 \ud55c \uc0ac\ub78c\uc774\ub77c\ub3c4 \uc783\uc5b4\ubc84\ub9ac\uc9c0 \uc54a\uc73c\uc2dc\uace0 \ub05d\uae4c\uc9c0 \ucc3e\uc73c\uc138\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uaed8 \ub3cc\uc544\uac00\uace0 \uc788\ub098\uc694?")
B.WQ=new A.b8("luke-lesson-16","path-luke","\uc7ac\ubb3c\uacfc \uc601\uc6d0\ud55c \uac00\uce58","\ub204\uac00\ubcf5\uc74c 16\uc7a5","\uc608\uc218\ub2d8\uc740 \ubd88\uc758\ud55c \uccad\uc9c0\uae30\uc758 \ube44\uc720\ub97c \ud1b5\ud574 \uc9c0\ud61c\ub86d\uac8c \uc0b4\uc544\uc57c \ud568\uc744 \uac00\ub974\uce58\uc138\uc694. \uc7ac\ubb3c\uc740 \uc601\uc6d0\ud558\uc9c0 \uc54a\uc73c\uba70 \ud558\ub098\ub2d8\uacfc \uc7ac\ubb3c\uc744 \ub3d9\uc2dc\uc5d0 \uc12c\uae38 \uc218 \uc5c6\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \ubb34\uc5c7\uc744 \uac00\uc7a5 \uc911\uc694\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?")
B.WH=new A.b8("luke-lesson-17","path-luke","\uac10\uc0ac\uc640 \ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uc778\uc2dd","\ub204\uac00\ubcf5\uc74c 17\uc7a5","\uc608\uc218\ub2d8\uc740 \uc6a9\uc11c\uc640 \ubbff\uc74c\uc758 \uc911\uc694\uc131\uc744 \uac00\ub974\uce58\uc138\uc694. \uc5f4 \uba85\uc758 \ub098\ubcd1\ud658\uc790\uac00 \uace0\uce68\uc744 \ubc1b\uc9c0\ub9cc \uc624\uc9c1 \ud55c \uc0ac\ub78c\ub9cc \ub3cc\uc544\uc640 \uac10\uc0ac\ud574\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uaed8 \uac10\uc0ac\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694?")
B.Wn=new A.b8("luke-lesson-18","path-luke","\uacb8\uc190\uacfc \ub048\uae30 \uc788\ub294 \ubbff\uc74c","\ub204\uac00\ubcf5\uc74c 18\uc7a5","\uc608\uc218\ub2d8\uc740 \ub048\uc9c8\uae30\uac8c \uad6c\ud558\ub294 \uacfc\ubd80\uc758 \ube44\uc720\ub97c \ud1b5\ud574 \uae30\ub3c4\uc758 \uc911\uc694\uc131\uc744 \uac00\ub974\uce58\uc138\uc694. \ubc14\ub9ac\uc0c8\uc778\uacfc \uc138\ub9ac\uc758 \uae30\ub3c4\ub97c \ud1b5\ud574 \uacb8\uc190\ud55c \ud0dc\ub3c4\uac00 \ud558\ub098\ub2d8\uaed8 \ubc1b\uc544\ub4e4\uc5ec\uc9c4\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uaed8 \uacc4\uc18d \ub098\uc544\uac00\uace0 \uc788\ub098\uc694?")
B.Wo=new A.b8("luke-lesson-19","path-luke","\ud68c\uac1c\uc640 \ucc45\uc784 \uadf8\ub9ac\uace0 \uc655 \ub418\uc2e0 \uc608\uc218\ub2d8","\ub204\uac00\ubcf5\uc74c 19\uc7a5","\uc0ad\uac1c\uc624\ub294 \uc608\uc218\ub2d8\uc744 \ub9cc\ub098 \uc0b6\uc774 \uc644\uc804\ud788 \ubcc0\ud654\ub3fc\uc694. \uc608\uc218\ub2d8\uc740 \uc783\uc740 \uc790\ub97c \ucc3e\uc544 \uad6c\uc6d0\ud558\ub7ec \uc624\uc168\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \ubcc0\ud654\ub41c \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?")
B.Wd=new A.b8("luke-lesson-20","path-luke","\uad8c\uc704\uc5d0 \ub300\ud55c \ud0dc\ub3c4","\ub204\uac00\ubcf5\uc74c 20\uc7a5","\uc885\uad50 \uc9c0\ub3c4\uc790\ub4e4\uc740 \uc608\uc218\ub2d8\uc758 \uad8c\uc704\ub97c \uc778\uc815\ud558\uc9c0 \uc54a\uc73c\ub824 \ud574\uc694. \ud3ec\ub3c4\uc6d0 \ub18d\ubd80 \ube44\uc720\ub97c \ud1b5\ud574 \ud558\ub098\ub2d8\uc744 \uac70\ubd80\ud558\ub294 \ubaa8\uc2b5\uc744 \ub4dc\ub7ec\ub0b4\uc138\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \uad8c\uc704\ub97c \uc778\uc815\ud558\uace0 \uc788\ub098\uc694?")
B.Wz=new A.b8("luke-lesson-21","path-luke","\ud5cc\uc2e0\uacfc \uc900\ube44\ub41c \uc0b6","\ub204\uac00\ubcf5\uc74c 21\uc7a5","\ud55c \uacfc\ubd80\uc758 \ud5cc\uae08\uc744 \ud1b5\ud574 \uc9c4\uc9dc \ud5cc\uc2e0\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubcf4\uc5ec\uc8fc\uc138\uc694. \uc608\uc218\ub2d8\uc740 \ub9c8\uc9c0\ub9c9 \ub54c\uc758 \uc9d5\uc870\ub97c \ub9d0\uc500\ud558\uc2dc\uba70 \uc900\ube44\ub41c \uc0b6\uc744 \uac15\uc870\ud558\uc138\uc694.","\ub098\ub294 \uc9c4\uc2ec\uc73c\ub85c \ud558\ub098\ub2d8\uaed8 \ub4dc\ub9ac\uace0 \uc788\ub098\uc694?")
B.WJ=new A.b8("luke-lesson-22","path-luke","\uace0\ub09c \uc18d\uc5d0\uc11c\uc758 \uc21c\uc885\uacfc \uc5f0\uc57d\ud568","\ub204\uac00\ubcf5\uc74c 22\uc7a5","\uc608\uc218\ub2d8\uc740 \uc81c\uc790\ub4e4\uacfc \ub9c8\uc9c0\ub9c9 \ub9cc\ucc2c\uc744 \ub098\ub204\uc2dc\uba70 \uc790\uc2e0\uc758 \ud76c\uc0dd\uc744 \uc900\ube44\ud558\uc138\uc694. \uc81c\uc790\ub4e4\uc740 \ub2e4\ud22c\uace0 \ud754\ub4e4\ub9ac\uba70 \uc720\ub2e4\ub294 \ubc30\uc2e0\ud574\uc694.","\ub098\ub294 \uc5b4\ub824\uc6c0 \uc18d\uc5d0\uc11c\ub3c4 \ud558\ub098\ub2d8\uc744 \ub530\ub974\uace0 \uc788\ub098\uc694?")
B.Wt=new A.b8("luke-lesson-23","path-luke","\uc2ed\uc790\uac00\uc640 \uc6a9\uc11c","\ub204\uac00\ubcf5\uc74c 23\uc7a5","\uc608\uc218\ub2d8\uc740 \uc8c4\uac00 \uc5c6\uc73c\uc2dc\uc9c0\ub9cc \uc2ed\uc790\uac00\uc5d0\uc11c \uace0\ub09c\uc744 \ubc1b\uc73c\uc138\uc694. \uc0ac\ub78c\ub4e4\uc740 \uc870\ub871\ud558\uc9c0\ub9cc \uc608\uc218\ub2d8\uc740 \uc6a9\uc11c\uc758 \uae30\ub3c4\ub97c \ud558\uc138\uc694.","\ub098\ub294 \uc6a9\uc11c\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694?")
B.X6=new A.b8("luke-lesson-24","path-luke","\ubd80\ud65c\uacfc \uc0c8\ub85c\uc6b4 \uc2dc\uc791","\ub204\uac00\ubcf5\uc74c 24\uc7a5","\uc608\uc218\ub2d8\uc740 \uc8fd\uc74c\uc744 \uc774\uae30\uace0 \ubd80\ud65c\ud558\uc138\uc694. \uc81c\uc790\ub4e4\uc740 \ucc98\uc74c\uc5d0\ub294 \ubbff\uc9c0 \ubabb\ud558\uc9c0\ub9cc \uc608\uc218\ub2d8\uc744 \ub9cc\ub098\uba70 \ubbff\uc74c\uc774 \ud68c\ubcf5\ub3fc\uc694.","\ub098\ub294 \ubd80\ud65c\uc744 \uc9c4\uc9dc \ubbff\uace0 \uc788\ub098\uc694?")
