B.a9w=new A.aW("\uc608\uc218\ub2d8\uc740 \ub204\uad6c\uc2e0\uac00","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \u201c\uc2dc\uac04\ud45c\u201d\ub97c \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?","\uc544\ube0c\ub77c\ud568\ubd80\ud130 \uc608\uc218\ub2d8\uae4c\uc9c0\ub294 \uc544\uc8fc \uae34 \uc2dc\uac04\uc774 \uac78\ub838\uc9c0\ub9cc,\n\ud558\ub098\ub2d8\uc740 \uadf8 \uc57d\uc18d\uc744 \ub05d\uae4c\uc9c0 \uc774\ub8e8\uc168\uc5b4\uc694.\n\ub098\ub294 \ub0b4 \uc0b6\uc5d0\uc11c\ub3c4\n\uc9c0\uae08 \ub2f9\uc7a5 \ubcf4\uc774\uc9c0 \uc54a\uc544\ub3c4 \ud558\ub098\ub2d8\uc774 \uc77c\ud558\uace0 \uacc4\uc2ec\uc744 \ubbff\uace0 \uc788\ub098\uc694?",1)
B.aa7=new A.aW("\uc608\uc218\ub2d8\uc740 \ub204\uad6c\uc2e0\uac00","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \uc774\uc57c\uae30 \uc548\uc5d0 \uc788\ub294 \uc0ac\ub78c\uc774\ub77c\uace0 \uc0dd\uac01\ud558\ub098\uc694?","\uacc4\ubcf4\uc5d0 \ub098\uc624\ub294 \uc0ac\ub78c\ub4e4\uc740 \ud3c9\ubc94\ud55c \uc774\ub984\ucc98\ub7fc \ubcf4\uc774\uc9c0\ub9cc,\n\uacb0\uad6d \ud558\ub098\ub2d8\uc758 \uad6c\uc6d0 \uc5ed\uc0ac\uc5d0 \uc5f0\uacb0\ub41c \uc0ac\ub78c\ub4e4\uc774\uc5d0\uc694.\n\n\ub098\ub294 \ub0b4 \uc0b6\uc774 \ub2e8\uc21c\ud55c \uac1c\uc778\uc758 \uc774\uc57c\uae30\uac00 \uc544\ub2c8\ub77c\n\ud558\ub098\ub2d8\uc758 \ud070 \uacc4\ud68d \uc548\uc5d0 \uc788\ub2e4\uace0 \ubbff\uace0 \uc788\ub098\uc694?",1)
B.aaw=new A.aW("\uc608\uc218\ub2d8\uc740 \ub204\uad6c\uc2e0\uac00","\ub098\ub294 \u201c\uc774\uc5b4\uc9c0\ub294 \ubbff\uc74c\u201d\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uacc4\ubcf4\ub294 \ud55c \uc138\ub300\uc5d0\uc11c \ub2e4\uc74c \uc138\ub300\ub85c \uacc4\uc18d \uc774\uc5b4\uc9c0\uba70\n\ud558\ub098\ub2d8\uc758 \uc57d\uc18d\uc774 \uc804\ub2ec\ub418\ub294 \ubaa8\uc2b5\uc744 \ubcf4\uc5ec\uc918\uc694.\n\n\ub098\ub294 \ub0b4 \uc0b6\uc744 \ud1b5\ud574\n\ubbff\uc74c\uc774 \ub2e4\uc74c \uc0ac\ub78c\uc5d0\uac8c \uc774\uc5b4\uc9c0\ub3c4\ub85d \uc0b4\uace0 \uc788\ub098\uc694?",1)
B.a9N=new A.aW("\uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd","\ub098\ub294 \uc774\ud574\ub418\uc9c0 \uc54a\ub294 \uc0c1\ud669\uc5d0\uc11c\ub3c4 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc2e0\ub8b0\ud560 \uc218 \uc788\ub098\uc694?","\uc694\uc149\uc740 \ucc98\uc74c\uc5d0\ub294 \uc774\ud574\ud560 \uc218 \uc5c6\uc5c8\uc9c0\ub9cc\n\ud558\ub098\ub2d8\uc758 \ub9d0\uc500\uc744 \ub4e3\uace0 \uc21c\uc885\ud558\ub294 \uc120\ud0dd\uc744 \ud588\uc5b4\uc694.\n\n\ub098\ub294 \ub0a9\ub4dd\uc774 \ub418\uc9c0 \uc54a\uc544\ub3c4\n\ud558\ub098\ub2d8\uc758 \ub9d0\uc500\uc744 \ub530\ub77c\uac08 \uc218 \uc788\ub098\uc694?",1)
B.a9Z=new A.aW("\uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd","\ub098\ub294 \u2018\uc758\ub85c\uc6c0\u2019\uc744 \uc5b4\ub5bb\uac8c \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?","\ub2f9\uc2dc \uc728\ubc95\ub300\ub85c\ub77c\uba74 \ub9c8\ub9ac\uc544\ub97c \ub4dc\ub7ec\ub0b4\uace0 \uad00\uacc4\ub97c \ub04a\ub294 \uac83\ub3c4 \uac00\ub2a5\ud55c \uc120\ud0dd\uc774\uc5c8\uc9c0\ub9cc,\n\uc694\uc149\uc740 \ud558\ub098\ub2d8\uc758 \uacc4\uc2dc\ub97c \ub4e4\uc740 \ud6c4\n\uc790\uc2e0\uc758 \ud310\ub2e8\uacfc \uae30\uc900\uc744 \ub0b4\ub824\ub193\uace0 \ud558\ub098\ub2d8\uc758 \ub73b\uc5d0 \uc790\uc2e0\uc744 \ub9e1\uacbc\uc5b4\uc694.\n\n\ub098\ub294 \ub0b4 \uae30\uc900\uc5d0\uc11c \u201c\uc633\ub2e4\u201d\uace0 \uc0dd\uac01\ud558\ub294 \uac83\uc5d0 \uba38\ubb34\ub974\ub294\uac00\uc694,\n\uc544\ub2c8\uba74 \ud558\ub098\ub2d8\uc758 \ub73b\uc774 \ub4dc\ub7ec\ub0a0 \ub54c \ub0b4 \ud310\ub2e8\uc744 \ub0b4\ub824\ub193\uace0 \uc21c\uc885\ud558\uace0 \uc788\ub098\uc694?",1)
B.aaD=new A.aW("\uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd","\uc608\uc218\ub2d8\uc774 \u2018\ub098\uc758 \uad6c\uc6d0\uc790\u2019\ub77c\ub294 \uc0ac\uc2e4\uc774 \uc2e4\uc81c\ub85c \ub290\uaef4\uc9c0\ub098\uc694?","\uc608\uc218\ub77c\ub294 \uc774\ub984\uc5d0\ub294\n\u201c\uc8c4\uc5d0\uc11c \uad6c\uc6d0\ud558\uc2dc\ub294 \ubd84\u201d\uc774\ub77c\ub294 \uc758\ubbf8\uac00 \ub2f4\uaca8 \uc788\uc5b4\uc694.\n\n\ub098\ub294 \uc608\uc218\ub2d8\uc744 \ub2e8\uc21c\ud55c \uc778\ubb3c\uc774 \uc544\ub2c8\ub77c\n\ub0b4 \uc0b6\uc744 \ubcc0\ud654\uc2dc\ud0a4\ub294 \uad6c\uc6d0\uc790\ub85c \ubc1b\uc544\ub4e4\uc774\uace0 \uc788\ub098\uc694?",1)
B.aaa=new A.aW("\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ud558\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \uc608\uc218\ub2d8\uaed8 \ub098\uc544\uac00\ub294 \uc0ac\ub78c\uc778\uac00\uc694, \ud53c\ud558\ub294 \uc0ac\ub78c\uc778\uac00\uc694?","\ubc15\uc0ac\ub4e4\uc740 \uba3c \uae38\uc744 \uc640\uc11c \uc608\uc218\ub2d8\uaed8 \uacbd\ubc30\ud588\uc9c0\ub9cc,\n\ud5e4\ub86f\uc740 \ub450\ub824\uc6cc\ud558\uba70 \uac70\ubd80\ud588\uc5b4\uc694.\n\n\ub098\ub294 \uc608\uc218\ub2d8\uc744\n\uae30\uc068\uc73c\ub85c \ucc3e\uace0 \uc788\ub098\uc694, \uc544\ub2c8\uba74 \ubd80\ub2f4\uc2a4\ub7ec\uc6cc\ud558\uace0 \uc788\ub098\uc694?",2)
B.aaz=new A.aW("\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ud558\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8\uc774 \uc8fc\uc2dc\ub294 \uc778\ub3c4\ud558\uc2ec\uc744 \ub530\ub974\uace0 \uc788\ub098\uc694?","\ubc15\uc0ac\ub4e4\uacfc \uc694\uc149\uc740 \uafc8\uacfc \ub9d0\uc500\uc744 \ud1b5\ud574\n\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ub97c \ubc1b\uace0 \uadf8\ub300\ub85c \ub530\ub790\uc5b4\uc694.\n\n\ub098\ub294 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc54c \ub54c\n\uc21c\uc885\uc73c\ub85c \ubc18\uc751\ud558\uace0 \uc788\ub098\uc694?",2)
B.aab=new A.aW("\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ud558\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8\uaed8 \ubb34\uc5c7\uc744 \ub4dc\ub9ac\uace0 \uc788\ub098\uc694?","\ubc15\uc0ac\ub4e4\uc740 \uadc0\ud55c \uc608\ubb3c\uc744 \uac00\uc9c0\uace0 \ub098\uc544\uac00\n\uc608\uc218\ub2d8\uaed8 \ub4dc\ub838\uc5b4\uc694.\n\n\ub098\ub294 \uc608\uc218\ub2d8\uaed8\n\uc2dc\uac04, \ub9c8\uc74c, \uc0b6\uc744 \uc9c4\uc2ec\uc73c\ub85c \ub4dc\ub9ac\uace0 \uc788\ub098\uc694?",2)
B.aaH=new A.aW("\ud68c\uac1c\uc640 \uc21c\uc885\uc73c\ub85c \uc900\ube44\ub418\ub294 \uc0b6","\ub098\ub294 \uc9c4\uc9dc \ud68c\uac1c\ud558\uace0 \uc788\ub098\uc694?","\uc138\ub840 \uc694\ud55c\uc740 \ub2e8\uc21c\ud55c \ub9d0\uc774 \uc544\ub2c8\ub77c\n\uc0b6\uc758 \ubcc0\ud654\ub85c \ub098\ud0c0\ub098\ub294 \ud68c\uac1c\ub97c \uac15\uc870\ud588\uc5b4\uc694.\n\n\ub098\ub294 \uc785\uc73c\ub85c\ub9cc\uc774 \uc544\ub2c8\ub77c\n\uc0b6\uc73c\ub85c \ubcc0\ud654\ub418\ub294 \ud68c\uac1c\ub97c \ud558\uace0 \uc788\ub098\uc694?",3)
B.a9U=new A.aW("\ud68c\uac1c\uc640 \uc21c\uc885\uc73c\ub85c \uc900\ube44\ub418\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uacb8\uc190\ud55c\uac00\uc694?","\uc138\ub840 \uc694\ud55c\uc740 \ub9ce\uc740 \uc0ac\ub78c\ub4e4\uc5d0\uac8c \uc778\uc815\ubc1b\uc558\uc9c0\ub9cc\n\uc790\uc2e0\uc744 \ub0ae\ucd94\uace0 \uc608\uc218\ub2d8\uc744 \ub192\uc600\uc5b4\uc694.\n\n\ub098\ub294 \uc778\uc815\ubc1b\uc744 \ub54c\n\ub098\ub97c \ub4dc\ub7ec\ub0b4\uace0 \uc788\ub294\uac00, \ud558\ub098\ub2d8\uc744 \ub4dc\ub7ec\ub0b4\uace0 \uc788\ub098\uc694?",3)
B.a9C=new A.aW("\ud68c\uac1c\uc640 \uc21c\uc885\uc73c\ub85c \uc900\ube44\ub418\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \ub73b\uc5d0 \uc21c\uc885\ud558\uace0 \uc788\ub098\uc694?","\uc608\uc218\ub2d8\uc870\ucc28 \u201c\ubaa8\ub4e0 \uc758\ub97c \uc774\ub8e8\uae30 \uc704\ud574\u201d\n\uc138\ub840\ub97c \ubc1b\uc73c\uba70 \ud558\ub098\ub2d8\uc758 \ub73b\uc5d0 \uc21c\uc885\ud558\uc168\uc5b4\uc694.\n\n\ub098\ub294 \uc774\ud574\uac00 \ub418\ub4e0 \uc548 \ub418\ub4e0\n\ud558\ub098\ub2d8\uc758 \ub73b \uc55e\uc5d0 \uc21c\uc885\ud558\uace0 \uc788\ub098\uc694?",3)
B.a9O=new A.aW("\ub9d0\uc500\uc73c\ub85c \uc2dc\ud5d8\uc744 \uc774\uae30\uace0 \ubd80\ub974\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \uc720\ud639 \uc55e\uc5d0\uc11c \ubb34\uc5c7\uc744 \uae30\uc900\uc73c\ub85c \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?","\uc720\ud639\uc740 \ud53c\ud560 \uc218 \uc5c6\uc9c0\ub9cc, \uc5b4\ub5bb\uac8c \ubc18\uc751\ud560\uc9c0\ub294 \uc120\ud0dd\ud560 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uac10\uc815\uc774\ub098 \uc0c1\ud669\uc774 \uc544\ub2c8\ub77c \ud558\ub098\ub2d8\uc758 \ub9d0\uc500\uc744 \uae30\uc900\uc73c\ub85c \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?",4)
B.aaq=new A.aW("\ub9d0\uc500\uc73c\ub85c \uc2dc\ud5d8\uc744 \uc774\uae30\uace0 \ubd80\ub974\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \ubd80\ub974\uc2ec\uc5d0 \uc989\uc2dc \ubc18\uc751\ud558\uace0 \uc788\ub098\uc694?","\uc81c\uc790\ub4e4\uc740 \uc900\ube44\ub41c \ud6c4\uc5d0 \ub530\ub978 \uac83\uc774 \uc544\ub2c8\ub77c \ubd80\ub974\uc2ec \uc55e\uc5d0\uc11c \ubc14\ub85c \ubc18\uc751\ud588\uc5b4\uc694. \ub098\ub294 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc54c\uba74\uc11c\ub3c4 \ubbf8\ub8e8\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?",4)
B.a9x=new A.aW("\ub9d0\uc500\uc73c\ub85c \uc2dc\ud5d8\uc744 \uc774\uae30\uace0 \ubd80\ub974\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \ub9d0\uc500\uc744 \uc544\ub294 \uac83\uc744 \ub118\uc5b4 \uc0b4\uc544\ub0b4\uace0 \uc788\ub098\uc694?","\ub9d0\uc500\uc744 \uc544\ub294 \uac83\uacfc \uc2e4\uc81c\ub85c \uc0ac\ub294 \uac83\uc740 \ub2ec\ub77c\uc694. \ub098\ub294 \ub4e4\uc740 \ub9d0\uc500\uc744 \uc0b6\uc5d0\uc11c \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?",4)
B.a9z=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ubc31\uc131\uc774 \uc0b4\uc544\uac00\ub294 \uc0b6\uc758 \uae30\uc900","\ub098\ub294 \uc138\uc0c1\uc758 \uae30\uc900\uc774 \uc544\ub2cc \ud558\ub098\ub2d8 \uae30\uc900\uc73c\ub85c \uc0b4\uace0 \uc788\ub098\uc694?","\uc138\uc0c1\uc740 \uc131\uacf5, \uc778\uc815, \ud3b8\uc548\ud568\uc744 \uae30\uc900\uc73c\ub85c \ubcf5\uc744 \ub9d0\ud574\uc694. \ud558\uc9c0\ub9cc \ud558\ub098\ub2d8\uc740 \uc804\ud600 \ub2e4\ub978 \uae30\uc900\uc744 \ub9d0\uc500\ud558\uc138\uc694. \ub098\ub294 \uc5b4\ub5a4 \uae30\uc900\uc73c\ub85c \uc0b6\uc744 \ud310\ub2e8\ud558\uace0 \uc788\ub098\uc694?",5)
B.aao=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ubc31\uc131\uc774 \uc0b4\uc544\uac00\ub294 \uc0b6\uc758 \uae30\uc900","\ub098\ub294 \uac89\ubaa8\uc2b5\uc774 \uc544\ub2c8\ub77c \ub9c8\uc74c\uae4c\uc9c0 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc815\uc9c1\ud55c\uac00\uc694?","\uc0ac\ub78c\ub4e4\uc740 \ud589\ub3d9\ub9cc \ubcf4\uc9c0\ub9cc \ud558\ub098\ub2d8\uc740 \ub9c8\uc74c\uc744 \ubcf4\uc138\uc694. \ub098\ub294 \uac89\uc73c\ub85c\ub9cc \uad1c\ucc2e\uc740 \ucc99\ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?",5)
B.aaj=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ubc31\uc131\uc774 \uc0b4\uc544\uac00\ub294 \uc0b6\uc758 \uae30\uc900","\ub098\ub294 \uc6d0\uc218\uae4c\uc9c0 \uc0ac\ub791\ud558\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc0ac\ub791\ud558\uae30 \uc26c\uc6b4 \uc0ac\ub78c\ub9cc \uc0ac\ub791\ud558\ub294 \uac83\uc740 \ub204\uad6c\ub098 \ud560 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ub098\ub97c \ud798\ub4e4\uac8c \ud558\ub294 \uc0ac\ub78c\uc5d0\uac8c\ub3c4 \ud558\ub098\ub2d8\uc758 \ubc29\uc2dd\uc73c\ub85c \uc0ac\ub791\ud558\uace0 \uc788\ub098\uc694?",5)
B.a9R=new A.aW("\ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\uc758 \uc9c4\uc9dc \uacbd\uac74\uacfc \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704","\ub098\ub294 \ud558\ub098\ub2d8\uc774 \uc544\ub2c8\ub77c \uc0ac\ub78c\uc744 \uc758\uc2dd\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694?","\uac89\uc73c\ub85c \ub4dc\ub7ec\ub098\ub294 \ud589\ub3d9\ubcf4\ub2e4 \uc911\uc694\ud55c \uac83\uc740 \ub9c8\uc74c\uc758 \ub3d9\uae30\uc608\uc694. \ub098\ub294 \ud558\ub098\ub2d8\uaed8 \ubcf4\uc774\uae30 \uc704\ud574 \uc0b4\uace0 \uc788\ub098\uc694, \uc544\ub2c8\uba74 \uc0ac\ub78c\uc5d0\uac8c \uc778\uc815\ubc1b\uae30 \uc704\ud574 \uc0b4\uace0 \uc788\ub098\uc694?",6)
B.a9y=new A.aW("\ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\uc758 \uc9c4\uc9dc \uacbd\uac74\uacfc \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc2e0\ub8b0\ud558\uba70 \uc5fc\ub824\ub97c \ub0b4\ub824\ub193\uace0 \uc788\ub098\uc694?","\uc5fc\ub824\ub294 \ud558\ub098\ub2d8\uc744 \ubbff\uc9c0 \ubabb\ud560 \ub54c \ucee4\uc838\uc694. \ub098\ub294 \ubb38\uc81c\ubcf4\ub2e4 \ud558\ub098\ub2d8\uc744 \ub354 \ud06c\uac8c \ubcf4\uace0 \uc788\ub098\uc694?",6)
B.a9H=new A.aW("\ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\uc758 \uc9c4\uc9dc \uacbd\uac74\uacfc \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704","\ub098\ub294 \ud558\ub098\ub2d8 \ub098\ub77c\ub97c \uac00\uc7a5 \uc6b0\uc120\uc73c\ub85c \ub450\uace0 \uc788\ub098\uc694?","\ub9ce\uc740 \uac83\ub4e4\uc774 \uc911\uc694\ud574 \ubcf4\uc774\uc9c0\ub9cc \uc9c4\uc9dc \uc6b0\uc120\uc21c\uc704\ub294 \ud558\ub098\ub2d8\uc774\uc5d0\uc694. \ub098\ub294 \uc9c0\uae08 \ubb34\uc5c7\uc744 \uac00\uc7a5 \uba3c\uc800 \ub450\uace0 \uc0b4\uace0 \uc788\ub098\uc694?",6)
B.a9T=new A.aW("\ucc38\ub41c \uc81c\uc790\uc758 \uc0b6\uacfc \uc120\ud0dd","\ub098\ub294 \ub9d0\uc500\uc744 \ub4e3\ub294 \uac83\uc5d0\uc11c \ub05d\ub098\uace0 \uc788\ub098\uc694, \uc544\ub2c8\uba74 \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?","\uc544\ub294 \uac83\uacfc \uc0ac\ub294 \uac83\uc740 \ub2ec\ub77c\uc694. \ub098\ub294 \ub9d0\uc500\uc744 \uc0b6\uc5d0 \uc801\uc6a9\ud558\uace0 \uc788\ub098\uc694?",7)
B.aa2=new A.aW("\ucc38\ub41c \uc81c\uc790\uc758 \uc0b6\uacfc \uc120\ud0dd","\ub098\ub294 \uc26c\uc6b4 \uae38\uc774 \uc544\ub2c8\ub77c \uc633\uc740 \uae38\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?","\ub113\uc740 \uae38\uc740 \ud3b8\ud558\uc9c0\ub9cc \uacb0\uad6d \uc0dd\uba85\uc774 \uc544\ub2c8\uc5d0\uc694. \ub098\ub294 \uc5b4\ub5a4 \uae38\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?",7)
B.aa_=new A.aW("\ucc38\ub41c \uc81c\uc790\uc758 \uc0b6\uacfc \uc120\ud0dd","\ub098\ub294 \ub0b4 \uc0b6\uc758 \uae30\ucd08\ub97c \uc5b4\ub514\uc5d0 \ub450\uace0 \uc788\ub098\uc694?","\uc0c1\ud669\uc774 \ud754\ub4e4\ub9b4 \ub54c \ub4dc\ub7ec\ub098\ub294 \uac83\uc774 \uae30\ucd08\uc608\uc694. \ub098\ub294 \ubb34\uc5c7 \uc704\uc5d0 \ub0b4 \uc0b6\uc744 \uc138\uc6b0\uace0 \uc788\ub098\uc694?",7)
B.aaQ=new A.aW("\uc608\uc218\ub2d8\uc758 \uad8c\uc704\uc640 \ubbff\uc74c","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \uad8c\uc704\ub97c \uc5bc\ub9c8\ub098 \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?","\ubb38\uc81c\uc758 \ud06c\uae30\ubcf4\ub2e4 \uc608\uc218\ub2d8\uc758 \ub2a5\ub825\uc744 \ub354 \ud06c\uac8c \ubcf4\uace0 \uc788\ub098\uc694?",8)
