B.a9Y=new A.aW("\uc608\uc218\ub2d8\uc758 \uad8c\uc704\uc640 \ubbff\uc74c","\ub098\ub294 \ub450\ub824\uc6c0 \uc18d\uc5d0\uc11c\ub3c4 \ubbff\uc74c\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?","\uc0c1\ud669\uc774 \ud754\ub4e4\ub9b4 \ub54c \ubbff\uc74c\uc774 \ub4dc\ub7ec\ub098\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?",8)
B.aaf=new A.aW("\uc8c4\ub97c \uc0ac\ud558\uc2dc\uace0 \uc0ac\ub78c\uc744 \ubd80\ub974\uc2dc\ub294 \uc608\uc218\ub2d8","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \ubd80\ub974\uc2ec\uc5d0 \uc751\ub2f5\ud558\uace0 \uc788\ub098\uc694?","\ub9c8\ud0dc\ub294 \uc989\uc2dc \ub530\ub790\uc5b4\uc694. \ub098\ub294 \ubbf8\ub8e8\uace0 \uc788\uc9c0 \uc54a\ub098\uc694?",9)
B.aa0=new A.aW("\uc8c4\ub97c \uc0ac\ud558\uc2dc\uace0 \uc0ac\ub78c\uc744 \ubd80\ub974\uc2dc\ub294 \uc608\uc218\ub2d8","\ub098\ub294 \ub098\uc758 \uc8c4 \ubb38\uc81c\ub97c \uc608\uc218\ub2d8\uaed8 \ub9e1\uae30\uace0 \uc788\ub098\uc694?","\uac89 \ubb38\uc81c\uac00 \uc544\ub2c8\ub77c \uc8c4\uac00 \ub354 \uadfc\ubcf8\uc774\uc5d0\uc694. \ub098\ub294 \uadf8\uac83\uc744 \uc778\uc815\ud558\uace0 \uc788\ub098\uc694?",9)
B.aas=new A.aW("\uc8c4\ub97c \uc0ac\ud558\uc2dc\uace0 \uc0ac\ub78c\uc744 \ubd80\ub974\uc2dc\ub294 \uc608\uc218\ub2d8","\ub098\ub294 \uc0ac\ub78c\uc744 \ubd88\uc30d\ud788 \uc5ec\uae30\ub294 \ub9c8\uc74c\uc774 \uc788\ub098\uc694?","\uc608\uc218\ub2d8\uc740 \uc0ac\ub78c\uc744 \ud310\ub2e8\ud558\uc9c0 \uc54a\uace0 \ubd88\uc30d\ud788 \uc5ec\uae30\uc168\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4 \ub9c8\uc74c\uc778\uac00\uc694?",9)
B.a9A=new A.aW("\uc81c\uc790\uc758 \uc0ac\uba85\uacfc \ub300\uac00","\ub098\ub294 \ubcf5\uc74c\uc744 \uc804\ud558\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\ubbff\uc74c\uc740 \ud63c\uc790\ub9cc\uc758 \uac83\uc774 \uc544\ub2c8\uc5d0\uc694. \ub098\ub294 \ub0b4 \uc8fc\ubcc0 \uc0ac\ub78c\ub4e4\uc5d0\uac8c \ubcf5\uc74c\uc744 \ub098\ub204\uace0 \uc788\ub098\uc694?",10)
B.a9u=new A.aW("\uc81c\uc790\uc758 \uc0ac\uba85\uacfc \ub300\uac00","\ub098\ub294 \uc0ac\ub78c\ubcf4\ub2e4 \ud558\ub098\ub2d8\uc744 \ub354 \ub450\ub824\uc6cc\ud558\uace0 \uc788\ub098\uc694?","\uc0ac\ub78c\uc758 \uc2dc\uc120\uc774 \ub354 \uc911\uc694\ud574\uc9c8 \ub54c\uac00 \ub9ce\uc544\uc694. \ub098\ub294 \ub204\uad6c\ub97c \uae30\uc900\uc73c\ub85c \uc0b4\uace0 \uc788\ub098\uc694?",10)
B.aaN=new A.aW("\uc81c\uc790\uc758 \uc0ac\uba85\uacfc \ub300\uac00","\ub098\ub294 \uc608\uc218\ub2d8\uc744 \ub530\ub974\uae30 \uc704\ud574 \ub098\ub97c \ub0b4\ub824\ub193\uc744 \uc218 \uc788\ub098\uc694?","\uc81c\uc790\ub294 \ud3b8\ud55c \uae38\uc774 \uc544\ub2c8\ub77c \ud5cc\uc2e0\uc758 \uae38\uc774\uc5d0\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \ubd99\uc7a1\uace0 \uc788\ub098\uc694?",10)
