B.a9W=new A.aW("\uc608\uc218\ub2d8\uc744 \ud5a5\ud55c \ubc18\uc751\uacfc \ucc38\ub41c \uc27c","\ub098\ub294 \uc608\uc218\ub2d8\uaed8 \ub098\uc544\uac00 \uc27c\uc744 \uc5bb\uace0 \uc788\ub098\uc694?","\uc0ac\ub78c\uacfc \ud658\uacbd\uc5d0\uc11c \uc27c\uc744 \ucc3e\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \uc9c4\uc9dc \uc27c\uc740 \uc5b4\ub514\uc5d0 \uc788\ub098\uc694?",11)
B.aau=new A.aW("\uc608\uc218\ub2d8\uc744 \ud5a5\ud55c \ubc18\uc751\uacfc \ucc38\ub41c \uc27c","\ub098\ub294 \uacb8\uc190\ud55c \ub9c8\uc74c\uc73c\ub85c \ud558\ub098\ub2d8\uc744 \ubc14\ub77c\ubcf4\uace0 \uc788\ub098\uc694?","\uad50\ub9cc\ud558\uba74 \ud558\ub098\ub2d8\uc744 \ubcfc \uc218 \uc5c6\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4 \ub9c8\uc74c \uc0c1\ud0dc\uc778\uac00\uc694?",11)
B.aaP=new A.aW("\ucc38\ub41c \uc548\uc2dd\uacfc \ub9c8\uc74c\uc758 \uc0c1\ud0dc","\ub098\ub294 \ud615\uc2dd\uc801\uc778 \uc2e0\uc559\uc5d0 \uba38\ubb3c\ub7ec \uc788\ub098\uc694?","\uac89\uc73c\ub85c\ub294 \uc798\ud558\ub294 \uac83\ucc98\ub7fc \ubcf4\uc5ec\ub3c4 \ub9c8\uc74c\uc740 \ub2e4\ub97c \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4\uac00\uc694?",12)
B.aak=new A.aW("\ucc38\ub41c \uc548\uc2dd\uacfc \ub9c8\uc74c\uc758 \uc0c1\ud0dc","\ub098\ub294 \ud558\ub098\ub2d8\ubcf4\ub2e4 \uaddc\uce59\uc744 \ub354 \uc911\uc694\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?","\uaddc\uce59\ub3c4 \uc911\uc694\ud558\uc9c0\ub9cc \uc911\uc2ec\uc740 \ud558\ub098\ub2d8\uc774\uc5d0\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \ub354 \uc911\uc694\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?",12)
B.aaC=new A.aW("\ucc38\ub41c \uc548\uc2dd\uacfc \ub9c8\uc74c\uc758 \uc0c1\ud0dc","\ub098\ub294 \ub0b4 \ub9c8\uc74c\uc744 \uc798 \uc0b4\ud53c\uace0 \uc788\ub098\uc694?","\ud589\ub3d9\ubcf4\ub2e4 \ub354 \uc911\uc694\ud55c \uac83\uc740 \ub9c8\uc74c\uc774\uc5d0\uc694. \ub098\ub294 \ub0b4 \uc18d\uc744 \ub3cc\uc544\ubcf4\uace0 \uc788\ub098\uc694?",12)
