B.a9B=new A.aW("\uc608\uc218\ub2d8\uc758 \uc815\uccb4\uc131\uacfc \uc81c\uc790\uc758 \uae38","\ub098\ub294 \uc2ed\uc790\uac00\ub97c \uc9c0\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\ud3b8\ud55c \uc2e0\uc559\uc774 \uc544\ub2c8\ub77c \ud5cc\uc2e0\uc774 \ud544\uc694\ud574\uc694. \ub098\ub294 \uc5b4\ub5a4 \uc120\ud0dd\uc744 \ud558\uace0 \uc788\ub098\uc694?",16)
