B.aaJ=new A.aW("\ud558\ub098\ub2d8\uc758 \uc601\uad11\uacfc \ubbff\uc74c","\ub098\ub294 \ub9d0\uc500\uc5d0 \uc9d1\uc911\ud558\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8\uc740 \u201c\uadf8\uc758 \ub9d0\uc744 \ub4e4\uc73c\ub77c\u201d\uace0 \ud558\uc168\uc5b4\uc694. \ub098\ub294 \ub4e3\uace0 \uc788\ub098\uc694?",17)
B.aaL=new A.aW("\uacb8\uc190\uacfc \uc6a9\uc11c\uc758 \uacf5\ub3d9\uccb4","\ub098\ub294 \ub0ae\uc544\uc9c0\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc138\uc0c1\uc5d0\uc11c\ub294 \ub192\uc544\uc9c0\ub294 \uac83\uc774 \uc911\uc694\ud558\uc9c0\ub9cc \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0\uc11c\ub294 \ub0ae\uc544\uc9c0\ub294 \uac83\uc774 \ub354 \uc911\uc694\ud574\uc694. \ub098\ub294 \uc778\uc815\ubc1b\uace0 \ub192\uc544\uc9c0\ub824\ub294 \ub9c8\uc74c\uc774 \ub354 \ud070\uac00\uc694, \uc544\ub2c8\uba74 \ub0b4\ub824\ub193\uc73c\ub824\ub294 \ub9c8\uc74c\uc774 \uc788\ub098\uc694? \uc624\ub298 \ub0b4\uac00 \ub0ae\uc544\uc9c8 \uc218 \uc788\ub294 \uc120\ud0dd\uc740 \ubb34\uc5c7\uc778\uac00\uc694?",18)
B.a9v=new A.aW("\uacb8\uc190\uacfc \uc6a9\uc11c\uc758 \uacf5\ub3d9\uccb4","\ub098\ub294 \ub2e4\ub978 \uc0ac\ub78c\uc744 \uc9c4\uc2ec\uc73c\ub85c \uc6a9\uc11c\ud558\uace0 \uc788\ub098\uc694?","\uc6a9\uc11c\ub294 \uac10\uc815\uc774 \uc544\ub2c8\ub77c \uc120\ud0dd\uc774\uc5d0\uc694. \ub9c8\uc74c\uc774 \ub530\ub77c\uc624\uc9c0 \uc54a\ub354\ub77c\ub3c4 \uba3c\uc800 \uc6a9\uc11c\ub97c \uc120\ud0dd\ud574\uc57c \ud574\uc694. \ub098\ub294 \uc544\uc9c1 \ub9c8\uc74c\uc18d\uc5d0 \ub0b4\ub824\ub193\uc9c0 \ubabb\ud55c \uc0ac\ub78c\uc774 \uc788\ub098\uc694?",18)
B.aar=new A.aW("\uacb8\uc190\uacfc \uc6a9\uc11c\uc758 \uacf5\ub3d9\uccb4","\ub098\ub294 \ud55c \uc0ac\ub78c\uc744 \uc18c\uc911\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8\uc740 \ud55c \uc601\ud63c\ub3c4 \ud3ec\uae30\ud558\uc9c0 \uc54a\uc73c\uc138\uc694. \ub098\ub294 \uc0ac\ub78c\uc744 \uc22b\uc790\ub098 \uc870\uac74\uc73c\ub85c \ud310\ub2e8\ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \ub0b4 \uc8fc\ubcc0\uc5d0\uc11c \ub0b4\uac00 \ub354 \uad00\uc2ec \uac00\uc838\uc57c \ud560 \uc0ac\ub78c\uc740 \ub204\uad6c\uc778\uac00\uc694?",18)
B.aa6=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uc640 \uacb0\ub2e8","\ub098\ub294 \ud558\ub098\ub2d8\ubcf4\ub2e4 \ub354 \ubd99\uc7a1\uace0 \uc788\ub294 \uac83\uc774 \uc788\ub098\uc694?","\ud558\ub098\ub2d8\uc744 \ub530\ub974\uae30 \uc704\ud574\uc11c\ub294 \ub0b4\ub824\ub193\uc544\uc57c \ud560 \uac83\uc774 \uc788\uc744 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ud3ec\uae30\ud558\uc9c0 \ubabb\ud558\uace0 \ubd99\uc7a1\uace0 \uc788\ub294 \uac83\uc774 \ubb34\uc5c7\uc778\uac00\uc694? \uadf8\uac83\uc774 \ud558\ub098\ub2d8\ubcf4\ub2e4 \ub354 \uc911\uc694\ud55c \uc790\ub9ac\uc5d0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?",19)
B.aaO=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uc640 \uacb0\ub2e8","\ub098\ub294 \uc5b4\ub9b0\uc544\uc774 \uac19\uc740 \ub9c8\uc74c\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?","\uc5b4\ub9b0\uc544\uc774\ub294 \uc2a4\uc2a4\ub85c \ud574\uacb0\ud558\ub824 \ud558\uc9c0 \uc54a\uace0 \uc758\uc9c0\ud574\uc694. \ub098\ub294 \ub0b4 \ud798\uc73c\ub85c\ub9cc \uc0b4\uc544\uac00\ub824\uace0 \ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \ud558\ub098\ub2d8\uc744 \uc5bc\ub9c8\ub098 \uc758\uc9c0\ud558\uace0 \uc788\ub098\uc694?",19)
B.aaA=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uc640 \uacb0\ub2e8","\ub098\ub294 \uc9c4\uc9dc\ub85c \uc608\uc218\ub2d8\uc744 \ub530\ub974\uace0 \uc788\ub098\uc694?","\ub9d0\ub85c\ub294 \ub530\ub974\ub294 \uac83\ucc98\ub7fc \ubcf4\uc5ec\ub3c4 \uc2e4\uc81c \uc120\ud0dd\uc740 \ub2e4\ub97c \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704\ub97c \uc608\uc218\ub2d8\uaed8 \ub450\uace0 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \uc5ec\uc804\ud788 \ub2e4\ub978 \uac83\ub4e4\uc774 \ub354 \uc55e\uc11c\uace0 \uc788\ub098\uc694?",19)
B.aa4=new A.aW("\uc740\ud61c\uc640 \uc12c\uae40\uc758 \uc6d0\ub9ac","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \uc740\ud61c\ub97c \ub2f9\uc5f0\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?","\ub0b4\uac00 \ubc1b\uc740 \uac83\uc740 \ub0b4\uac00 \uc798\ud574\uc11c\uac00 \uc544\ub2c8\ub77c \ud558\ub098\ub2d8\uc774 \uc8fc\uc2e0 \uc740\ud61c\uc608\uc694. \ub098\ub294 \uadf8\uac83\uc744 \uac10\uc0ac\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \ub2e4\ub978 \uc0ac\ub78c\uacfc \ube44\uad50\ud558\uba70 \ubd88\ud3c9\ud558\uace0 \uc788\ub098\uc694?",20)
B.aal=new A.aW("\uc740\ud61c\uc640 \uc12c\uae40\uc758 \uc6d0\ub9ac","\ub098\ub294 \uc12c\uae30\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc12c\uae40\uc740 \ub9d0\uc774 \uc544\ub2c8\ub77c \ud589\ub3d9\uc73c\ub85c \ub4dc\ub7ec\ub098\uc694. \ub098\ub294 \ub0ae\uc544\uc9c0\ub294 \uc120\ud0dd\uc744 \ud558\uace0 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \uc778\uc815\ubc1b\uc73c\ub824\ub294 \ub9c8\uc74c\uc774 \ub354 \ud070\uac00\uc694?",20)
B.aah=new A.aW("\uc740\ud61c\uc640 \uc12c\uae40\uc758 \uc6d0\ub9ac","\ub098\ub294 \ub2e4\ub978 \uc0ac\ub78c\uacfc \ube44\uad50\ud558\uace0 \uc788\ub098\uc694?","\ube44\uad50\ub294 \uac10\uc0ac\ubcf4\ub2e4 \ubd88\ub9cc\uc744 \ub9cc\ub4e4\uc5b4\uc694. \ub098\ub294 \ub204\uad6c\uc640 \ub098\ub97c \ube44\uad50\ud558\uace0 \uc788\ub098\uc694? \ud558\ub098\ub2d8\uc774 \ub098\uc5d0\uac8c \uc8fc\uc2e0 \uac83\uc5d0 \uc9d1\uc911\ud558\uace0 \uc788\ub098\uc694?",20)
B.a9L=new A.aW("\uc655\uc73c\ub85c \uc624\uc2e0 \uc608\uc218\ub2d8\uacfc \uc5f4\ub9e4","\ub098\ub294 \uc5f4\ub9e4 \uc788\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc2e0\uc559\uc740 \ub9d0\uc774 \uc544\ub2c8\ub77c \uc0b6\uc758 \uc5f4\ub9e4\ub85c \ub4dc\ub7ec\ub098\uc694. \ub098\ub294 \uac89\uc73c\ub85c\ub9cc \ubbff\ub294 \uac83\ucc98\ub7fc \ubcf4\uc774\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc2e4\uc81c\ub85c \ubcc0\ud654\ub41c \ubaa8\uc2b5\uc774 \ub098\ud0c0\ub098\uace0 \uc788\ub098\uc694?",21)
B.aay=new A.aW("\uc655\uc73c\ub85c \uc624\uc2e0 \uc608\uc218\ub2d8\uacfc \uc5f4\ub9e4","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \uad8c\uc704\ub97c \uc778\uc815\ud558\uace0 \uc788\ub098\uc694?","\uc608\uc218\ub2d8\uc740 \ub0b4 \uc0b6\uc758 \uc8fc\uc778\uc774\uc138\uc694. \ub098\ub294 \uadf8\ubd84\uc758 \ub9d0\uc500\uc744 \uae30\uc900\uc73c\ub85c \uc0b4\uace0 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \ub0b4 \uae30\uc900\uc744 \ub354 \uc55e\uc138\uc6b0\uace0 \uc788\ub098\uc694?",21)
B.aam=new A.aW("\uc655\uc73c\ub85c \uc624\uc2e0 \uc608\uc218\ub2d8\uacfc \uc5f4\ub9e4","\ub098\ub294 \ub9d0\uacfc \ud589\ub3d9\uc774 \uc77c\uce58\ud558\uace0 \uc788\ub098\uc694?","\ub9d0\ub85c\ub294 \uc21c\uc885\ud55c\ub2e4\uace0 \ud558\uba74\uc11c \uc2e4\uc81c \ud589\ub3d9\uc740 \ub2e4\ub97c \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ub9d0\ubfd0\uc778 \uc2e0\uc559\uc744 \uac00\uc9c0\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \uc624\ub298 \ub0b4\uac00 \ubc14\uafd4\uc57c \ud560 \ud589\ub3d9\uc740 \ubb34\uc5c7\uc778\uac00\uc694?",21)
B.a9M=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ucd08\ub300\uc640 \uc0ac\ub791\uc758 \uacc4\uba85","\ub098\ub294 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \uc900\ube44\ub41c \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\ucd08\ub300\ubc1b\ub294 \uac83\ub9cc\uc73c\ub85c \ucda9\ubd84\ud558\uc9c0 \uc54a\uc544\uc694. \ub098\ub294 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \ud569\ub2f9\ud558\uac8c \uc900\ube44\ub418\uc5b4 \uc788\ub098\uc694? \ub0b4 \uc0b6\uc740 \uadf8 \uae30\uc900\uc5d0 \ub9de\uac8c \ubcc0\ud654\ub418\uace0 \uc788\ub098\uc694?",22)
B.a9J=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ucd08\ub300\uc640 \uc0ac\ub791\uc758 \uacc4\uba85","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc9c4\uc2ec\uc73c\ub85c \uc0ac\ub791\ud558\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8 \uc0ac\ub791\uc740 \ub9d0\uc774 \uc544\ub2c8\ub77c \uc6b0\uc120\uc21c\uc704\ub85c \ub4dc\ub7ec\ub098\uc694. \ub098\ub294 \ud558\ub098\ub2d8\uc744 \uac00\uc7a5 \uba3c\uc800 \ub450\uace0 \uc788\ub098\uc694? \ub0b4 \uc120\ud0dd\uacfc \uc2dc\uac04\uc740 \ubb34\uc5c7\uc744 \ubcf4\uc5ec\uc8fc\uace0 \uc788\ub098\uc694?",22)
B.a9S=new A.aW("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ucd08\ub300\uc640 \uc0ac\ub791\uc758 \uacc4\uba85","\ub098\ub294 \uc774\uc6c3\uc744 \uc0ac\ub791\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8 \uc0ac\ub791\uc740 \ubc18\ub4dc\uc2dc \uc0ac\ub78c \uc0ac\ub791\uc73c\ub85c \uc774\uc5b4\uc838\uc694. \ub098\ub294 \uc8fc\ubcc0 \uc0ac\ub78c\ub4e4\uc744 \uc5b4\ub5bb\uac8c \ub300\ud558\uace0 \uc788\ub098\uc694? \ubd88\ud3b8\ud55c \uc0ac\ub78c\uc5d0\uac8c\ub3c4 \uc0ac\ub791\uc744 \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?",22)
B.aac=new A.aW("\uc678\uc2dd\uc774 \uc544\ub2cc \ucc38\ub41c \uc2e0\uc559","\ub098\ub294 \uac89\uacfc \uc18d\uc774 \uac19\uc740 \uc2e0\uc559\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?","\uc0ac\ub78c\uc5d0\uac8c \ubcf4\uc774\ub294 \ubaa8\uc2b5\uacfc \uc2e4\uc81c \ubaa8\uc2b5\uc774 \ub2e4\ub97c \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\ub3c4 \ub3d9\uc77c\ud55c \ubaa8\uc2b5\uc73c\ub85c \uc11c \uc788\ub098\uc694? \ub0b4 \uc2e0\uc559\uc740 \uc9c4\uc9dc\uc778\uac00\uc694?",23)
B.aaK=new A.aW("\uc678\uc2dd\uc774 \uc544\ub2cc \ucc38\ub41c \uc2e0\uc559","\ub098\ub294 \uc0ac\ub78c\uc758 \uc2dc\uc120\uc744 \ub354 \uc758\uc2dd\ud558\uace0 \uc788\ub098\uc694?","\uc778\uc815\ubc1b\uace0 \uc2f6\uc740 \ub9c8\uc74c\uc740 \uc790\uc5f0\uc2a4\ub7fd\uc9c0\ub9cc \uae30\uc900\uc774 \ub418\uba74 \uc704\ud5d8\ud574\uc694. \ub098\ub294 \ub204\uad6c\ub97c \ub354 \uc758\uc2dd\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694? \ud558\ub098\ub2d8\uc774 \ubcf4\uc2dc\ub294 \uac83\uc744 \ub354 \uc911\uc694\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?",23)
B.a9P=new A.aW("\uc678\uc2dd\uc774 \uc544\ub2cc \ucc38\ub41c \uc2e0\uc559","\ub098\ub294 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc815\uc9c1\ud55c\uac00\uc694?","\uc228\uae30\uace0 \uc2f6\uc740 \ubaa8\uc2b5\uc774 \uc788\uc744 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uadf8\uac83\uc744 \ud558\ub098\ub2d8\uaed8 \uc194\uc9c1\ud558\uac8c \ub0b4\uc5b4\ub193\uace0 \uc788\ub098\uc694? \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc815\uc9c1\ud558\uac8c \uc0b4\uace0 \uc788\ub098\uc694?",23)
B.aav=new A.aW("\uae68\uc5b4 \uc900\ube44\ud558\ub294 \uc0b6","\ub098\ub294 \uc900\ube44\ub41c \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc5b8\uc820\uac00\uac00 \uc544\ub2c8\ub77c \uc9c0\uae08\uc774 \uc911\uc694\ud574\uc694. \ub098\ub294 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc900\ube44\ub41c \uc0c1\ud0dc\uc778\uac00\uc694? \uc9c0\uae08 \ub0b4 \uc0b6\uc744 \uc810\uac80\ud574\ubcfc \ud544\uc694\uac00 \uc788\uc9c0 \uc54a\ub098\uc694?",24)
B.aa1=new A.aW("\uae68\uc5b4 \uc900\ube44\ud558\ub294 \uc0b6","\ub098\ub294 \uc601\uc801\uc73c\ub85c \uae68\uc5b4 \uc788\ub098\uc694?","\uc775\uc219\ud568\uc740 \uc2e0\uc559\uc744 \ubb34\ub514\uac8c \ub9cc\ub4e4 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ud558\ub098\ub2d8\uacfc\uc758 \uad00\uacc4\uac00 \uc0b4\uc544 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \ud615\uc2dd\uc801\uc73c\ub85c \ud750\ub974\uace0 \uc788\ub098\uc694?",24)
B.aaF=new A.aW("\uae68\uc5b4 \uc900\ube44\ud558\ub294 \uc0b6","\ub098\ub294 \ud604\uc7ac\ub97c \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc0b4\uace0 \uc788\ub098\uc694?","\ubbf8\ub798\ub97c \uac71\uc815\ud558\uba74\uc11c \ud604\uc7ac\ub97c \ub193\uce60 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uc9c0\uae08 \ud558\ub098\ub2d8\uacfc \ub3d9\ud589\ud558\uace0 \uc788\ub098\uc694? \uc624\ub298\uc744 \uc5b4\ub5bb\uac8c \uc0b4\uace0 \uc788\ub098\uc694?",24)
B.aaE=new A.aW("\uc900\ube44\uc640 \ucc45\uc784, \uadf8\ub9ac\uace0 \uc0ac\ub791\uc758 \uc2e4\ucc9c","\ub098\ub294 \uc900\ube44\ub41c \ubbff\uc74c\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?","\uc900\ube44\ub294 \ubbf8\ub8e8\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \uc9c0\uae08 \ud558\ub294 \uac83\uc774\uc5d0\uc694. \ub098\ub294 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc900\ube44\ub41c \uc0c1\ud0dc\uc778\uac00\uc694? \ub0b4 \uc0b6\uc740 \uae68\uc5b4 \uc788\ub098\uc694?",25)
B.a9K=new A.aW("\uc900\ube44\uc640 \ucc45\uc784, \uadf8\ub9ac\uace0 \uc0ac\ub791\uc758 \uc2e4\ucc9c","\ub098\ub294 \ub9e1\uaca8\uc9c4 \uac83\uc744 \uc798 \uc0ac\uc6a9\ud558\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8\uc740 \uac01\uc790\uc5d0\uac8c \ub9e1\uae30\uc2e0 \uac83\uc774 \uc788\uc5b4\uc694. \ub098\ub294 \uadf8\uac83\uc744 \uc5b4\ub5bb\uac8c \uc0ac\uc6a9\ud558\uace0 \uc788\ub098\uc694? \ud639\uc2dc \uc228\uae30\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?",25)
